<script setup>
import {reactive,ref} from 'vue';import {useRoute,useRouter} from 'vue-router';import {useAuthStore} from '../stores/auth';
const auth=useAuthStore(),router=useRouter(),route=useRoute(),mode=ref('login'),busy=ref(false),error=ref('');const form=reactive({name:'',email:'',password:'',password_confirmation:''});
async function submit(){busy.value=true;error.value='';try{mode.value==='login'?await auth.login(form):await auth.register(form);router.push(route.query.redirect||'/app/dashboard')}catch(e){error.value=e.response?.data?.message||Object.values(e.response?.data?.errors||{})[0]?.[0]||'Unable to continue.'}finally{busy.value=false}}
</script>
<template><div class="auth-page"><section class="auth-art"><img src="/media/Nenial.jpg"><h1>Build, sell, and operate with confidence.</h1><p>One secure workspace for storefront, POS, inventory, workforce, and fulfillment.</p></section><section class="auth-panel"><RouterLink to="/" class="back">← Back to store</RouterLink><form class="auth-card" @submit.prevent="submit"><span class="eyebrow">{{mode}}</span><h2>{{mode==='login'?'Welcome back':'Create customer account'}}</h2><label v-if="mode==='register'">Full name<input v-model="form.name" required></label><label>Email<input v-model="form.email" type="email" required></label><label>Password<input v-model="form.password" type="password" required minlength="8"></label><label v-if="mode==='register'">Confirm password<input v-model="form.password_confirmation" type="password" required></label><p v-if="error" class="error">{{error}}</p><button class="btn primary" :disabled="busy">{{busy?'Please wait…':mode==='login'?'Sign in':'Create account'}}</button><button type="button" class="text-button" @click="mode=mode==='login'?'register':'login'">{{mode==='login'?'Need a customer account? Register':'Already registered? Sign in'}}</button><small>Demo customer: demo.user@nenial.test / UserDemo2026!</small></form></section></div></template>
